module left_shift (
    input [3:0] in,
    output [3:0] out
);

    // Module supplies
    supply1 VPWR;
    supply0 VGND;

    // Local signals
    wire [3:0] data_reg;
    wire [3:0] shifted;

    // Assign the input to data_reg
    assign data_reg = in;

    // Shift the bits in data_reg to the left by one position and assign the result to shifted
    assign shifted = {data_reg[2:0], data_reg[3]};

    // Assign shifted to the output
    assign out = shifted;

endmodule
